#include<bits/stdc++.h>
using namespace std;
long long mod,phi[10000010];
long long fastpow(long long x,long long y,long long mod)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=(__int128)ans*x%mod;
        }
        x=(__int128)x*x%mod;
        y>>=1;
    }
    return ans;
}
long long dfs(long long x)
{
    if(x==1)
    {
        return 0;
    }
    return fastpow(2,dfs(phi[x])+phi[x],x);
}
int main()
{
    phi[1]=1;
    for(long long i=2;i<=10000000;i++)
    {
        if(phi[i]==0)
        {
            for(long long j=i;j<=10000000;j+=i)
            {
                if(phi[j]==0)
                {
                    phi[j]=j;
                }
                phi[j]=phi[j]/i*(i-1);
            }
        }
    }
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long p;
        scanf("%lld",&p);
        mod=p;
        printf("%lld\n",dfs(p));
    }
    return 0;
}
